// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/auth/info", wrapper.GetAuthInfo)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/oidc/exchange", wrapper.OidcExchange)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/runs", wrapper.ListRuns)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/runs", wrapper.CreateRun)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/api/runs/{id}", wrapper.CancelRun)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/runs/{id}", wrapper.GetRun)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/runs/{id}/events", wrapper.StreamRunEvents)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/scenarios", wrapper.ListScenarios)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/scenarios/{id}", wrapper.GetScenario)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/schedules", wrapper.ListSchedules)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/schedules", wrapper.CreateSchedule)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/api/schedules/{id}", wrapper.DeleteSchedule)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/schedules/{id}", wrapper.GetSchedule)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/schedules/{id}/pause", wrapper.PauseSchedule)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/schedules/{id}/resume", wrapper.ResumeSchedule)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/targets", wrapper.ListTargets)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/targets/{id}", wrapper.GetTarget)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/targets/{id}/test", wrapper.TestTargetConnection)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/healthz", wrapper.GetHealthz)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/internal/chaos", wrapper.CreateChaos)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/internal/chaos/{ref}", wrapper.DeleteChaos)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/readyz", wrapper.GetReadyz)
	})

	return r
}

